  @impl true
  def handle_call({:create_account, account_id, initial_balance}, _from, state) do
    case :ets.lookup(@table_name, account_id) do
      [] ->
        :ets.insert(@table_name, {account_id, initial_balance})
        log_entry = %{
          type: :create_account,
          account_id: account_id,
