      {:error, reason} ->
        {:reply, {:error, reason}, state}
    end
  end

  @impl true
  def handle_call({:deposit, account_id, amount}, _from, state) do
    case read_balance(account_id) do
      {:ok, current_balance} ->
        new_balance = current_balance + amount

        if validate_balance(new_balance) do
          :ets.insert(@table_name, {account_id, new_balance})
          log_entry = %{
            type: :deposit,
            account_id: account_id,
            amount: amount,
            previous_balance: current_balance,
            new_balance: new_balance,
            timestamp: DateTime.utc_now()
          }
          {:reply, {:ok, new_balance}, %{state | transaction_log: [log_entry | state.transaction_log]}}
        else
          {:reply, {:error, :invalid_balance}, state}
        end

      {:error, reason} ->
        {:reply, {:error, reason}, state}
    end
  end

