  def handle_call({:withdraw, account_id, amount}, _from, state) do
    case read_balance(account_id) do
      {:ok, current_balance} ->
        new_balance = current_balance - amount

        if validate_withdrawal(current_balance, amount) do
          :ets.insert(@table_name, {account_id, new_balance})
          log_entry = %{
            type: :withdrawal,
            account_id: account_id,
            amount: amount,
            previous_balance: current_balance,
            new_balance: new_balance,
            timestamp: DateTime.utc_now()
          }
          {:reply, {:ok, new_balance}, %{state | transaction_log: [log_entry | state.transaction_log]}}
        else
          {:reply, {:error, :insufficient_funds}, state}
        end

      {:error, reason} ->
        {:reply, {:error, reason}, state}
    end
  end

  @impl true
  def handle_call({:transfer, from_account, to_account, amount}, _from, state) do
    with {:ok, from_balance} <- read_balance(from_account),
         {:ok, to_balance} <- read_balance(to_account),
         true <- validate_withdrawal(from_balance, amount) do
      new_from_balance = from_balance - amount
      new_to_balance = to_balance + amount

      # Separate read, validate, then write operations (non-atomic)
      :ets.insert(@table_name, {from_account, new_from_balance})
      :ets.insert(@table_name, {to_account, new_to_balance})

      log_entry = %{
        type: :transfer,
        from_account: from_account,
        to_account: to_account,
        amount: amount,
        from_previous_balance: from_balance,
        from_new_balance: new_from_balance,
        to_previous_balance: to_balance,
        to_new_balance: new_to_balance,
        timestamp: DateTime.utc_now()
      }

      {:reply, {:ok, %{from_balance: new_from_balance, to_balance: new_to_balance}},
